var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`ATAC-130 건쉽, 선회 기동 지시를 대기 중.`,JPN:`ATAC-130ガンシップ、旋回起動指示まで待機中。`,ENG:`ATAC-130 Gunship, waiting for the command to turn...`,TWN:`ATAC-130 炮艦機，迴旋飛行指令待機中。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`라져. 최고경영자의 종신 계약 제안 접수.`,JPN:`了解。最高経営者の終身契約提案を受理。`,ENG:`Roger. The chief executive officer's lifetime contract offer accepted.`,TWN:`了解。已收到到最高經營管理者的終身契約提案。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`많은 개장을 거쳤지만, 본 기의 설계 이념은 현 시점에서 구식에 불과하다.`,JPN:`幾度もの改装を経てきたものの、本機の設計理念は、現時点においては旧式に他ならない。`,ENG:`I've been remodeled numerous times, but there's nothing that can be done to change my outdated design principles.`,TWN:`即使經過了許多改裝，但本機的設計理念在現時點，仍舊落後於時代。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`그럼에도 최고경영자는 본 기를 믿어 주었다.`,JPN:`にも関わらず、最高経営者は本機に信頼を寄せてくれている。`,ENG:`But you continued to trust me.`,TWN:`儘管如此，最高經營管理者仍然相信本機。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`군용 병기는 사용자의 신뢰에 부응하는 것이 우선 과제.`,JPN:`軍用兵器である本機にとって、使用者の信頼に応えることは優先的課題である。`,ENG:`The top priority of us military weapons is to respond to our users' trust.   `,TWN:`回應使用者的信賴是軍用兵器首要課題。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`인공지능의 성능상 섬세한 감정은 묘사할 수 없다. 따라서 보편적인 표현으로 대체하겠다.`,JPN:`人工知能の性能上、繊細な感情表現は困難である。ゆえに、普遍的な表現を取ることとする。`,ENG:`I'm incapable of exquisite expressions due to the limitations of my AI. I'll just have to use a general expression.`,TWN:`人工智慧的性能無法表達細膩的情感。有鑑於此，切換為普遍的表達方式……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`GUNSHIP_STATE_NULL_NULL`,text:{KOREA:`고맙다.`,JPN:`……感謝する。`,ENG:`Thank you.`,TWN:`謝謝。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`GUNSHIP_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};